    if (spec.viewportMode === 'manual' && spec.viewport) {
      const vp = spec.viewport
      return {
        xMin: vp.xMin ?? -10,
        xMax: vp.xMax ?? 10,
        yMin: vp.yMin ?? -10,
        yMax: vp.yMax ?? 10,
      }
    }
    // Otherwise return auto-calculated values
    return { xMin: -10, xMax: 10, yMin: -10, yMax: 10 }
  }),
}))

