  // FR-007: Frontend Rendering Integration
  describe('viewport handling', () => {
    it('passes manual viewport to JSXGraphBoard when viewportMode is manual', () => {
      const spec = createMockSpec({
        viewportMode: 'manual',
        viewport: { xMin: -5, xMax: 5, yMin: -20, yMax: 20 },
      })

      const { getByTestId } = render(<AxisRenderer blockId="test-id" spec={spec} />)

      const board = getByTestId('jsxgraph-board')
      const boundingBox = JSON.parse(board.getAttribute('data-bounding-box') || '[]')

      // Should use manual viewport values
      expect(boundingBox[0]).toBe(-5) // xMin
      expect(boundingBox[1]).toBe(20) // yMax
      expect(boundingBox[2]).toBe(5)  // xMax
      expect(boundingBox[3]).toBe(-20) // yMin
    })

    it('passes auto-calculated viewport to JSXGraphBoard when viewportMode is auto', () => {
      const spec = createMockSpec({
        viewportMode: 'auto',
        viewport: { xMin: -5, xMax: 5, yMin: -20, yMax: 20 }, // Manual values but should be ignored
        elements: {
