      const specWithoutMode = createMockSpec()
      // Remove viewportMode
      delete (specWithoutMode as Partial<AxisSpecV1>).viewportMode
      // Set manual viewport values but they should be ignored
      specWithoutMode.viewport = { xMin: -5, xMax: 5, yMin: -20, yMax: 20 }

      const { getByTestId } = render(<AxisRenderer blockId="test-id" spec={specWithoutMode} />)

      const board = getByTestId('jsxgraph-board')
      const boundingBox = JSON.parse(board.getAttribute('data-bounding-box') || '[]')

      // Should default to auto mode
      expect(boundingBox[0]).toBe(-10)
      expect(boundingBox[1]).toBe(10)
      expect(boundingBox[2]).toBe(10)
      expect(boundingBox[3]).toBe(-10)
    })
  })

  describe('grid and axis configuration', () => {
    it('passes grid enabled to JSXGraphBoard', () => {
      const spec = createMockSpec({
        grid: { enabled: true },
      })

      const { getByTestId } = render(<AxisRenderer blockId="test-id" spec={spec} />)

      // The mock should have been called with showGrid: true
      const board = getByTestId('jsxgraph-board')
      expect(board).toBeInTheDocument()
    })

    it('passes axis configuration to JSXGraphBoard', () => {
