// @vitest-environment jsdom
import { describe, expect, it, vi, afterEach } from 'vitest'
import { render, screen, fireEvent, cleanup } from '@testing-library/react'
import type { AxisSpecV1 } from '@/infra/contracts/graphics/axis.v1'
import { AxisConfigPanel } from '@/ui/admin/ExerciseContentEditor/components/axis/AxisConfigPanel'

afterEach(cleanup)

// Mock the viewport-utils to avoid implementation dependency
vi.mock('@/infra/utils/graphics/viewport-utils', () => ({
  calculateAutoViewport: vi.fn(() => ({ xMin: -10, xMax: 10, yMin: -10, yMax: 10 })),
  validateViewportRange: vi.fn(({ xMin, xMax, yMin, yMax }) => {
    const errors: string[] = []
    if (xMin >= xMax) errors.push('X-min must be less than X-max')
    if (yMin >= yMax) errors.push('Y-min must be less than Y-max')
    if (!Number.isFinite(xMin) || !Number.isFinite(xMax) || !Number.isFinite(yMin) || !Number.isFinite(yMax)) {
      errors.push('All values must be valid numbers')
    }
    return { valid: errors.length === 0, errors }
  }),
  checkGraphVisibility: vi.fn(() => ({ visible: true, warning: null })),
}))

const createMockSpec = (overrides: Partial<AxisSpecV1> = {}): AxisSpecV1 => ({
  kind: 'cartesian',
  units: 1,
  grid: { enabled: true },
  axes: {
    showNumbers: true,
    showLabels: true,
    ticks: 1,
    labels: { x: 'x', y: 'y' },
    origin: { x: 0, y: 0 },
  },
  viewportMode: 'auto',
  viewport: { xMin: -10, xMax: 10, yMin: -10, yMax: 10 },
  elements: {
    points: [],
    graphs: [],
  },
  ...overrides,
})

describe('AxisConfigPanel', () => {
  // FR-002: Manual Range Override Mode
  describe('auto/manual toggle', () => {
    it('renders without crashing when viewportMode is undefined (backward compat)', () => {
      const specWithoutMode = createMockSpec()
      delete (specWithoutMode as Partial<AxisSpecV1>).viewportMode

      const onChange = vi.fn()
      const { container } = render(<AxisConfigPanel spec={specWithoutMode} onChange={onChange} />)

      const checkbox = container.querySelector('input[type="checkbox"]')
      expect(checkbox).not.toBeNull()
    })

    it('Manual Range checkbox is unchecked by default when viewportMode is auto', () => {
      const spec = createMockSpec({ viewportMode: 'auto' })
      const onChange = vi.fn()

      render(<AxisConfigPanel spec={spec} onChange={onChange} />)

      const container = document.body.querySelector('input[type="checkbox"]')
      expect(container).not.toBeNull()
      if (container) {
        expect((container as HTMLInputElement).checked).toBe(false)
      }
    })

    it('Manual Range checkbox is checked when viewportMode is manual', () => {
      const spec = createMockSpec({ viewportMode: 'manual' })
      const onChange = vi.fn()

      const { container } = render(<AxisConfigPanel spec={spec} onChange={onChange} />)
      const checkbox = container.querySelector('input[type="checkbox"]')

      expect(checkbox).not.toBeNull()
      if (checkbox) {
        expect((checkbox as HTMLInputElement).checked).toBe(true)
      }
    })

    it('checking Manual Range checkbox calls onChange with viewportMode: manual', () => {
      const spec = createMockSpec({ viewportMode: 'auto' })
      const onChange = vi.fn()

      const { container } = render(<AxisConfigPanel spec={spec} onChange={onChange} />)
      const checkbox = container.querySelector('input[type="checkbox"]')

      if (checkbox) {
        fireEvent.click(checkbox)
      }

      expect(onChange).toHaveBeenCalled()
      const call = onChange.mock.calls[0][0] as AxisSpecV1
      expect(call.viewportMode).toBe('manual')
    })

    it('unchecking Manual Range checkbox calls onChange with viewportMode: auto', () => {
      const spec = createMockSpec({ viewportMode: 'manual' })
      const onChange = vi.fn()

      const { container } = render(<AxisConfigPanel spec={spec} onChange={onChange} />)
      const checkbox = container.querySelector('input[type="checkbox"]')

      if (checkbox) {
        fireEvent.click(checkbox)
      }

      expect(onChange).toHaveBeenCalled()
      const call = onChange.mock.calls[0][0] as AxisSpecV1
      expect(call.viewportMode).toBe('auto')
    })
  })

  // FR-003: Manual Range Input Fields
  describe('viewport input fields visibility', () => {
