      expect(hasDisabledInput).toBe(true)
    })

    it('viewport input fields are visible/enabled in manual mode', () => {
      const spec = createMockSpec({ viewportMode: 'manual' })
      const onChange = vi.fn()

      const { container } = render(<AxisConfigPanel spec={spec} onChange={onChange} />)
      const inputs = container.querySelectorAll('input[type="number"]')

