      const allDisabled = Array.from(inputs).every(input => (input as HTMLInputElement).disabled)
      expect(allDisabled).toBe(false)
    })
  })

  // FR-004: Min-Max Validation
  describe('validation errors', () => {
    it('shows error when xMin >= xMax', async () => {
