      })
      const onChange = vi.fn()

      const { container } = render(<AxisConfigPanel spec={spec} onChange={onChange} />)

      const errorText = container.textContent
      expect(errorText).toContain('must be a number')
    })
  })

  // FR-006: Empty Grid Warning
  describe('empty grid warning', () => {
    it('displays warning when graphs are not visible in viewport', () => {
      // Mock checkGraphVisibility to return not visible
      vi.mock('@/infra/utils/graphics/viewport-utils', () => ({
        calculateAutoViewport: vi.fn(() => ({ xMin: -10, xMax: 10, yMin: -10, yMax: 10 })),
        validateViewportRange: vi.fn(() => ({ valid: true, errors: [] })),
        checkGraphVisibility: vi.fn(() => ({
          visible: false,
          warning: 'Warning: No graph content is visible in the configured range.',
        })),
      }))

      const spec = createMockSpec({
        viewportMode: 'manual',
        viewport: { xMin: -10, xMax: 10, yMin: 100, yMax: 200 },
        elements: {
          points: [],
          graphs: [{ id: 'g1', fn: 'x^2', style: 'solid', thickness: 2 }],
        },
      })
      const onChange = vi.fn()

      const { container } = render(<AxisConfigPanel spec={spec} onChange={onChange} />)

      expect(container.textContent).toContain('No graph content is visible')
    })

    it('does not display warning when graphs are visible', () => {
      const spec = createMockSpec({
        viewportMode: 'manual',
        viewport: { xMin: -10, xMax: 10, yMin: -10, yMax: 10 },
